fn main() {
    let age: i32 = 30;
    let pi: f64 = 3.14;
    let active: bool = true;
    let grade: char = 'A';
    let pair = (age, pi);
    println!("{} {} {} {}", age, pi, active, grade);
    println!("{:?}", pair);
}

